import { NextRequest, NextResponse } from 'next/server';
import { MsEdgeTTS, OUTPUT_FORMAT } from 'msedge-tts';

/**
 * Alice_Neural_Studio v3.5
 * Integramos Voces Gratuitas de Microsoft Azure Edge (¡Extrema calidad y sin API Keys!)
 */

export async function POST(req: NextRequest) {
    try {
        const { text, voice = 'es-CO-SalomeNeural' } = await req.json();

        // 1. Prioridad: Microsoft Edge Neural TTS (Gratuito, Ilimitado, Alta Calidad Azure)
        try {
            const tts = new MsEdgeTTS();

            // Si eligieron un motor anterior, mapearlo a las nuevas voces Edge
            let selectedVoice = voice;
            if (voice === 'aura-2-es' || voice === 'shimmer') selectedVoice = 'es-CO-SalomeNeural'; // Colombiana joven
            if (voice === 'melotts') selectedVoice = 'es-ES-ElviraNeural'; // Española profesional
            if (voice === 'alloy' || voice === 'nova') selectedVoice = 'es-MX-DaliaNeural'; // Mexicana cálida

            await tts.setMetadata(selectedVoice, OUTPUT_FORMAT.AUDIO_24KHZ_48KBITRATE_MONO_MP3);

            const { audioStream } = tts.toStream(text);

            // Convertir el stream de NodeJS a un ReadableStream web para Edge (Reduce Latencia de 5s a 0.2s)
            const stream = new ReadableStream({
                start(controller) {
                    audioStream.on('data', chunk => {
                        controller.enqueue(new Uint8Array(chunk));
                    });
                    audioStream.on('close', () => {
                        controller.close();
                    });
                    audioStream.on('error', err => {
                        controller.error(err);
                    });
                }
            });

            return new NextResponse(stream, {
                headers: { 'Content-Type': 'audio/mpeg', 'Cache-Control': 'no-store', 'Transfer-Encoding': 'chunked' },
            });

        } catch (e) {
            console.error("[TTS] Edge TTS Exception:", e);
        }

        // 2. Fallback: OpenAI TTS si por casualidad falla algo y la env key está disponible
        const openAiKey = process.env.OPENAI_API_KEY;
        if (openAiKey) {
            const response = await fetch('https://api.openai.com/v1/audio/speech', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${openAiKey}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    model: 'tts-1-hd',
                    input: text,
                    voice: 'shimmer', // Shimmer es una voz femenina clara de OpenAI
                }),
            });

            if (response.ok) {
                const audioBuffer = await response.arrayBuffer();
                return new NextResponse(audioBuffer, {
                    headers: { 'Content-Type': 'audio/mpeg' },
                });
            }
        }

        // 3. Si todo falla
        return NextResponse.json({
            error: "No se pudieron conectar los motores neurales.",
        }, { status: 401 });

    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}
